tail -200 /tmp/openclaw/openclaw-2026-04-11.log 2>/dev/null | python3 -c "
import sys, json
lines = sys.stdin.readlines()
feishu_lines = []
for line in lines:
    try:
        d = json.loads(line)
        msg = str(d.get('1','')) + str(d.get('0',''))
        if 'feishu' in msg.lower() or 'lark' in msg.lower():
            feishu_lines.append(d)
    except:
        pass
print(f'Found {len(feishu_lines)} feishu-related log lines')
if feishu_lines:
    for l in feishu_lines[-5:]:
        print(l.get('time',''), l.get('1','')[:100])
" 2>/dev/null

tail -500 /tmp/openclaw/openclaw-2026-04-11.log 2>/dev/null | python3 -c "
import sys, json
lines = sys.stdin.readlines()
errors = []
channels_ok = []
for line in lines:
    try:
        d = json.loads(line)
        msg = str(d.get('1','')) + str(d.get('0',''))
        lvl = d.get('_meta',{}).get('logLevelName','')
        if lvl in ['ERROR','WARN'] and 'feishu' in msg.lower():
            errors.append((d.get('time',''), msg[:150]))
        if 'channel' in msg.lower() and 'ok' in msg.lower():
            channels_ok.append((d.get('time',''), msg[:150]))
    except:
        pass
print('Errors:')
for t,m in errors[-10:]:
    print(f'  {t}: {m}')
print('Channel OK:')
for t,m in channels_ok[-5:]:
    print(f'  {t}: {m}')
" 2>/dev/null

